1	// claim-office.ts
2	
3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	
23	const ITEM_BASE_PREMIUMS: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	  rune: 25,
29	  moonstone: 25,
30	};
31	
32	function sumItemBasePremiums(items: Item[]): number {
33	  return items.reduce(
34	    (sum, item) => sum + ITEM_BASE_PREMIUMS[item.type],
35	    0
36	  );
37	}
38	
39	function isBlockOfThreeRunes(items: Item[]): boolean {
40	  return items.length === 3 && items.every((item) => item.type === "rune");
41	}
42	
43	function calculatePolicyBase(items: Item[]): number {
44	  if (isBlockOfThreeRunes(items)) {
45	    return 60;
46	  }
47	  return sumItemBasePremiums(items);
48	}
49	
50	export function quote(input: QuoteInput): number {
51	  const policyBase = calculatePolicyBase(input.items);
52	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
53	  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
54	}
